import{_ as t,o,c as d,ah as a}from"./chunks/framework.Bi9enVNS.js";const h=JSON.parse('{"title":"归一化模型与推导规则","description":"","frontmatter":{},"headers":[],"relativePath":"reference/normalization.md","filePath":"reference/normalization.md","lastUpdated":1774205896000}'),r={name:"reference/normalization.md"};function c(i,e,n,l,s,p){return o(),d("div",null,[...e[0]||(e[0]=[a('<h1 id="归一化模型与推导规则" tabindex="-1">归一化模型与推导规则 <a class="header-anchor" href="#归一化模型与推导规则" aria-label="Permalink to &quot;归一化模型与推导规则&quot;">​</a></h1><p>VLT 的查询层不是直接返回原始 <code>LogRecord</code>，而是先把每条记录归一化成统一结构，再基于这个结构做 timeline、topology 和 sources 聚合。</p><h2 id="normalizedlogrecord" tabindex="-1"><code>NormalizedLogRecord</code> <a class="header-anchor" href="#normalizedlogrecord" aria-label="Permalink to &quot;`NormalizedLogRecord`&quot;">​</a></h2><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><code>log_id</code></td><td>原始日志 ID</td></tr><tr><td><code>project</code></td><td>所属项目</td></tr><tr><td><code>environment</code></td><td>所属环境</td></tr><tr><td><code>source_type</code></td><td>去掉前缀后的来源类型，如 <code>SERVICE</code></td></tr><tr><td><code>source_name</code></td><td>来源名称</td></tr><tr><td><code>source_id</code></td><td>来源 ID</td></tr><tr><td><code>instance_id</code></td><td>实例 ID</td></tr><tr><td><code>timestamp</code></td><td>取自 <code>event_time</code>，统一转为 UTC</td></tr><tr><td><code>severity_number</code></td><td>数值级别</td></tr><tr><td><code>severity_text</code></td><td>文本级别</td></tr><tr><td><code>logger_name</code></td><td>logger 名称</td></tr><tr><td><code>event_name</code></td><td>事件名称</td></tr><tr><td><code>body_text</code></td><td>面向搜索/展示的文本形态</td></tr><tr><td><code>body_json</code></td><td>原始 body 的 JSON 形态</td></tr><tr><td><code>attributes_json</code></td><td>属性 JSON</td></tr><tr><td><code>resource_json</code></td><td>批次资源 JSON</td></tr><tr><td><code>trace_id</code></td><td>Trace ID</td></tr><tr><td><code>span_id</code></td><td>Span ID</td></tr><tr><td><code>trace_flags</code></td><td>Trace flags</td></tr><tr><td><code>source_fingerprint</code></td><td>来源实例级聚合键</td></tr></tbody></table><h2 id="source-fingerprint-公式" tabindex="-1"><code>source_fingerprint</code> 公式 <a class="header-anchor" href="#source-fingerprint-公式" aria-label="Permalink to &quot;`source_fingerprint` 公式&quot;">​</a></h2><p>当前实现使用：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sha256(project | environment | source_type | source_name | instance_id)</span></span></code></pre></div><p>然后取前 16 个字节再编码为十六进制字符串。</p><h2 id="有效来源选择" tabindex="-1">有效来源选择 <a class="header-anchor" href="#有效来源选择" aria-label="Permalink to &quot;有效来源选择&quot;">​</a></h2><p>规则如下：</p><ol><li>如果 <code>LogRecord.source.source_name</code> 非空，使用记录级来源</li><li>否则回退到批次 <code>default_source</code></li></ol><h2 id="timeline-聚合" tabindex="-1">Timeline 聚合 <a class="header-anchor" href="#timeline-聚合" aria-label="Permalink to &quot;Timeline 聚合&quot;">​</a></h2><ul><li>先按 <code>trace_id</code> 找出记录</li><li>再按 <code>source_fingerprint</code> 聚合为 lanes</li><li>每个 lane 保留： <ul><li><code>event_count</code></li><li><code>error_count</code></li><li><code>first_seen</code></li><li><code>last_seen</code></li><li><code>events[]</code></li></ul></li><li><code>events[]</code> 按时间升序排列</li><li><code>event_id</code> 优先取 <code>log_id</code>；如果没有 <code>log_id</code>，回退为 <code>source_fingerprint/timestampUnixNano</code></li></ul><h2 id="topology-推导" tabindex="-1">Topology 推导 <a class="header-anchor" href="#topology-推导" aria-label="Permalink to &quot;Topology 推导&quot;">​</a></h2><ul><li>先按时间升序排列 Trace 记录</li><li>把连续相同 <code>source_fingerprint</code> 的记录折叠成 segment</li><li>对相邻 segment 生成一条边</li><li>相同方向的边会累计 <code>transition_count</code></li></ul><h2 id="错误数判定" tabindex="-1">错误数判定 <a class="header-anchor" href="#错误数判定" aria-label="Permalink to &quot;错误数判定&quot;">​</a></h2><p>当前实现中，错误记录定义为：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>severity_number &gt;= 17</span></span></code></pre></div><p>这会影响：</p><ul><li>timeline <code>error_count</code></li><li>topology node <code>error_count</code></li><li>topology edge <code>error_count</code></li></ul><h2 id="sources-聚合" tabindex="-1">Sources 聚合 <a class="header-anchor" href="#sources-聚合" aria-label="Permalink to &quot;Sources 聚合&quot;">​</a></h2><p>来源树的聚合顺序是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>source_type -&gt; source_name -&gt; instance_id</span></span></code></pre></div><p>如果 <code>instance_id</code> 为空，当前实现会把实例名写成 <code>-</code>。</p><h2 id="事实来源" tabindex="-1">事实来源 <a class="header-anchor" href="#事实来源" aria-label="Permalink to &quot;事实来源&quot;">​</a></h2><ul><li><code>internal/ingest/normalize.go</code></li><li><code>internal/store/store.go</code></li><li><code>internal/store/memory/memory.go</code></li></ul>',26)])])}const _=t(r,[["render",c]]);export{h as __pageData,_ as default};
